class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, char):
        if self.root is None:
            self.root = char
        else:
            self._insert(self.root, char)

    def _insert(self, current, char):
        if char < current:
            if current.left is None:
                current.left = char
            else:
                self._insert(current.left, char)
        else:
            if current.right is None:
                current.right = char
            else:
                self._insert(current.right, char)

def process_sequence(sequence):
    bst = BinarySearchTree()
    for char in sequence:
        bst.insert(char.lower())
    return bst

